#include<bits/stdc++.h>
using namespace std;
long long FUNCTION[50][50][50];
long long Function(long long x,long long y,long long z){
	if((x<=0)or(y<=0)or(z<=0))return 1;
	else if((x>20)or(y>20)or(z>20))return Function(20,20,20);
	if(FUNCTION[x][y][z]!=-1)return FUNCTION[x][y][z];
	else if((x<y)and(y<z))
		FUNCTION[x][y][z]=Function(x,y,z-1)+Function(x,y-1,z-1)-Function(x,y-1,z);
	else 
		FUNCTION[x][y][z]=Function(x-1,y,z)+Function(x-1,y-1,z)+Function(x-1,y,z-1)-Function(x-1,y-1,z-1);
	return FUNCTION[x][y][z];
}
int main(void){
    memset(FUNCTION,-1,sizeof(FUNCTION));
	long long X,Y,Z;
	while(true){
		cin>>X>>Y>>Z;
		if(X+Y+Z==-3)break;
		printf("w(%lld, %lld, %lld) = %lld\n",X,Y,Z,Function(X,Y,Z));
	}
    return false;
}
